parameters.jsCode:
const lead = $input.item.json;
const weekNum = Number(lead.week_to_send);
const programPlan = typeof lead.program_plan === 'string' ? JSON.parse(lead.program_plan) : (lead.program_plan || {});
const profile = typeof lead.user_profile === 'string' ? JSON.parse(lead.user_profile) : (lead.user_profile || {});
const weekPlan = programPlan[`week_${weekNum}`] || {};

const sessions = ['morning', 'midday', 'afternoon', 'evening'];
const pickImageUrl = (exercise = {}) => exercise.image_url || exercise.imageUrl || exercise.image || exercise.photo_url || exercise.photoUrl || '';
const mapExercise = (exercise) => exercise ? {
  name: exercise.name,
  description: exercise.description,
  image_url: pickImageUrl(exercise),
  cues: exercise.cues
} : null;

const weekPlanForPdf = {};
for (const s of sessions) {
  const slot = weekPlan[s] || {};
  weekPlanForPdf[s] = {
    warmup: mapExercise(slot.warmup),
    main: mapExercise(slot.main)
  };
}

const calendarMap = {
  1: $env.CALENDAR_WEEK1_URL || $env.CALENDAR_URL_WEEK1 || $env.CALENDAR_WEEK_1_URL || '',
  2: $env.CALENDAR_WEEK2_URL || $env.CALENDAR_URL_WEEK2 || $env.CALENDAR_WEEK_2_URL || '',
  3: $env.CALENDAR_WEEK3_URL || $env.CALENDAR_URL_WEEK3 || $env.CALENDAR_WEEK_3_URL || '',
  4: $env.CALENDAR_WEEK4_URL || $env.CALENDAR_URL_WEEK4 || $env.CALENDAR_WEEK_4_URL || ''
};
const calendarUrl = calendarMap[weekNum] || $env.CALENDAR_DEFAULT_URL || '';

return { json: {
  lead_id: lead.id,
  name: lead.name,
  email: lead.email,
  week_number: weekNum,
  template_key: `week_${weekNum}`,
  week_plan: weekPlanForPdf,
  profile: profile,
  calendar_url: calendarUrl
} };

const payload = $('Build PDF Payload').item.json;
const template = $input.item.json;

const fill = (str, vars) => String(str || '').replace(/{{\s*([a-zA-Z0-9_]+)\s*}}/g, (_, key) => vars[key] ?? '');

const vars = {
  name: payload.name || 'there',
  week_number: payload.week_number,
  calendar_url: payload.calendar_url || '',
  week_pdf_url: '',
  level2_offer_url: $env.LEVEL2_OFFER_URL || '',
  goal: payload.goal || payload.profile?.primary_goal || payload.profile?.goal || ''
};

return {
  json: {
    lead_id: payload.lead_id,
    name: payload.name,
    email: payload.email,
    week_number: payload.week_number,
    template_key: payload.template_key,
    week_plan: payload.week_plan,
    profile: payload.profile,
    calendar_url: payload.calendar_url,
    email_subject: fill(template.subject, vars),
    email_html: fill(template.html, vars),
    attachment_filename: `week${payload.week_number}-plan.pdf`
  }
};

